var oi_valor;
function onLoad()
{ 
	if(Ctrl('main').GetMode() !="LIST" && Ctrl('main').GetMode() !="LIST_EDIT")   
	{  
	  oi_valor = Ctrl("oi_valor").GetXValue(); 
	   if(oi_valor =='') 
	   {

 	  var factor = Ctrl("oi_factor_eval").GetXValue() != '' ? Ctrl("oi_factor_eval").GetXValue() : ""; 
 	  Ctrl("oi_factor_eval").SetWhere("CYD12_FACTORES_EVAL.oi_evaluacion ="+Ctrl('oi_evaluacion').GetXValue());
	  Ctrl("oi_factor_eval").SetXValue(factor);	
	  }
	  OnChange(); 
 	}

} 

function OnChange()
{

	 if(Ctrl("oi_factor_eval").GetXValue() != '')
	 {
	     var np, nSQL, i;

		 np = GetProxy();
		 nSQL = np.SQLService(); 	
		 var qry = Ctrl("main").getResource("qry_escala");

		 var result = nSQL.GetXML(qry,"<DATA oi_factor_eval='"+Ctrl("oi_factor_eval").GetXValue()+"' />");

		 //var oi_valor = Ctrl("oi_valor").GetXValue(); 
	     Ctrl('oi_valor').SetWhere("OI_FIND = '"+result.GetAttr("oi_escala")+"'"); 
	 	 //Ctrl('oi_valor').SetXValue(oi_valor); 
	 	 if(oi_valor !='') 
	 	 	Ctrl('oi_valor').SetXValue(oi_valor);
	 	 else
	 	 	Ctrl('oi_valor').SetXValue("");

	 	 oi_valor = ""; 
	 }

}
